// Nome da propriedade onde o arquivo está (geralmente 'data')
const binaryPropertyName = 'data';

for (const item of items) {
  if (item.binary && item.binary[binaryPropertyName]) {

    // --- PARTE 1: MUDAR O HASH ---
    // Decodifica o base64 para buffer
    const buffer = Buffer.from(item.binary[binaryPropertyName].data, 'base64');

    // Gera uma string aleatória pequena
    const randomString = Math.random().toString(36).substring(7);
    const metadataInjection = Buffer.from(randomString);

    // Concatena o buffer original com o lixo no final
    const newBuffer = Buffer.concat([buffer, metadataInjection]);

    // Salva de volta o novo conteúdo binário
    item.binary[binaryPropertyName].data = newBuffer.toString('base64');

    // --- PARTE 2: RENOMEAR O ARQUIVO ---
    const originalFileName = item.binary[binaryPropertyName].fileName || 'arquivo_sem_nome';

    // Separa nome da extensão
    const lastDotIndex = originalFileName.lastIndexOf('.');
    let name, extension;

    if (lastDotIndex !== -1) {
      name = originalFileName.substring(0, lastDotIndex);
      extension = originalFileName.substring(lastDotIndex); // inclui o ponto (ex: .mp4)
    } else {
      name = originalFileName;
      extension = '';
    }

    // Gera data formatada: YYYYMMDD_HHMMSS
    const now = new Date();
    const timestamp = now.toISOString().replace(/[-:T.]/g, '').slice(0, 14);

    // Define o novo nome
    item.binary[binaryPropertyName].fileName = `${name}_${timestamp}${extension}`;
  }
}

return items;

